const REVEAL_THRESHOLD=.15;function initScrollReveal(){const e=document.querySelectorAll(".reveal");e.length&&(observer=new IntersectionObserver(e=>{e.forEach(e=>{e.isIntersecting&&(e.target.classList.add("visible"),observer.unobserve(e.target))})},{threshold:.15}),e.forEach((e,t)=>{e.style.transitionDelay=50*t+"ms",observer.observe(e)}))}function initCaseTabs(){const e=document.querySelectorAll(".case-tab");e.length&&e.forEach(e=>{e.addEventListener("click",()=>{const t=e.getAttribute("data-tab"),a=e.closest("main");a.querySelectorAll(".case-tab").forEach(e=>e.classList.remove("active")),a.querySelectorAll(".case-tab-panel").forEach(e=>e.classList.remove("active")),e.classList.add("active");const s=a.querySelector(`.case-tab-panel[data-panel="${t}"]`);s&&(s.classList.add("active"),s.querySelectorAll(".reveal:not(.visible)").forEach(e=>{observer.observe(e)}))})})}let observer;document.addEventListener("DOMContentLoaded",()=>{initScrollReveal(),initCaseTabs()});